package com.cognizant.order.model;import jakarta.persistence.*;import java.math.BigDecimal;@Entity public class CustomerOrder{@Id @GeneratedValue(strategy=GenerationType.IDENTITY)private Long id;private Long userId;private String item;private BigDecimal amount;public Long getId(){return id;}public void setId(Long id){this.id=id;}public Long getUserId(){return userId;}public void setUserId(Long x){userId=x;}public String getItem(){return item;}public void setItem(String x){item=x;}public BigDecimal getAmount(){return amount;}public void setAmount(BigDecimal x){amount=x;}}